//! TLS 1.3 Cipher Tests
//!
//! This module tests the TLS 1.3 cipher decryption implementation using
//! test vectors generated by Python's cryptography library.

use tls_decryptor::cipher::suites::{
    Tls13Aes128GcmSha256, Tls13Aes256GcmSha384, Tls13ChaCha20Poly1305Sha256,
};
use tls_decryptor::cipher::trait_def::CipherContext;

use super::hex_to_bytes;
use super::load_test_vectors;

#[test]
fn test_tls13_aes_128_gcm_decrypt() {
    let vectors = load_test_vectors();
    let test = &vectors["tls13_tests"]["aes_128_gcm_basic"];

    let cipher = Tls13Aes128GcmSha256;
    let key = hex_to_bytes(test["key"].as_str().unwrap());
    let iv = hex_to_bytes(test["iv"].as_str().unwrap());
    let ciphertext = hex_to_bytes(test["full_ciphertext"].as_str().unwrap());
    let aad = hex_to_bytes(test["aad"].as_str().unwrap());
    let expected_plaintext = hex_to_bytes(test["plaintext"].as_str().unwrap());

    let result = cipher
        .decrypt(&key, &iv, &ciphertext, &aad, 0)
        .expect("TLS 1.3 AES-128-GCM decryption failed");

    assert_eq!(
        result, expected_plaintext,
        "TLS 1.3 AES-128-GCM plaintext mismatch"
    );
}

