#[test]
fn test_tls13_cipher_context_properties() {
    let aes128 = Tls13Aes128GcmSha256;
    assert_eq!(aes128.key_length(), 16);
    assert_eq!(aes128.iv_length(), 12);
    assert_eq!(aes128.tag_length(), 16);
    assert!(!aes128.needs_explicit_nonce());

    let aes256 = Tls13Aes256GcmSha384;
    assert_eq!(aes256.key_length(), 32);
    assert_eq!(aes256.iv_length(), 12);
    assert_eq!(aes256.tag_length(), 16);
    assert!(!aes256.needs_explicit_nonce());

    let chacha = Tls13ChaCha20Poly1305Sha256;
    assert_eq!(chacha.key_length(), 32);
    assert_eq!(chacha.iv_length(), 12);
    assert_eq!(chacha.tag_length(), 16);
    assert!(!chacha.needs_explicit_nonce());
}

#[test]
fn test_tls13_decrypt_invalid_key_length() {
    let cipher = Tls13Aes128GcmSha256;
    let key = vec![0u8; 8]; // Invalid key length
    let iv = vec![0u8; 12];
    let ciphertext = vec![0u8; 16];
    let aad = vec![];

    let result = cipher.decrypt(&key, &iv, &ciphertext, &aad, 0);
    assert!(result.is_err());
}

#[test]
fn test_tls13_decrypt_invalid_iv_length() {
    let cipher = Tls13Aes128GcmSha256;
    let key = vec![0u8; 16];
    let iv = vec![0u8; 8]; // Invalid IV length
    let ciphertext = vec![0u8; 16];
    let aad = vec![];

    let result = cipher.decrypt(&key, &iv, &ciphertext, &aad, 0);
    assert!(result.is_err());
}

#[test]
fn test_tls13_decrypt_insufficient_data() {
    let cipher = Tls13Aes128GcmSha256;
    let key = vec![0u8; 16];
    let iv = vec![0u8; 12];
    let ciphertext = vec![0u8; 4]; // Too short (less than tag length)
    let aad = vec![];

    let result = cipher.decrypt(&key, &iv, &ciphertext, &aad, 0);
    assert!(result.is_err());
}
